      sqlgen::strftime("%Y-%m-%d", &PageVisit::visit_time) | sqlgen::as<"visit_date">,
      sqlgen::count() | sqlgen::as<"total_visits">,
      sqlgen::count_distinct(&PageVisit::url) | sqlgen::as<"unique_pages">
    )
    | sqlgen::group_by(sqlgen::col<&PageVisit::visit_time>.strftime("%Y-%m-%d"))
    | sqlgen::order_by(sqlgen::col<&PageVisit::visit_time>.strftime("%Y-%m-%d"));

  // Execute the query and map results
  auto result_range = query(conn);
  if (!result_range) {
    throw std::runtime_error("Query execution failed");
  }

  // Convert the range to a vector of DailyTraffic structs
  std::vector<DailyTraffic> results;
  for (auto& row : *result_range) {
    results.emplace_back(
        std::get<0>(row).visit_date,
