  std::optional<std::string> title_keyword;
  std::optional<int> min_year;
  std::optional<std::string> genre;
  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    using namespace sqlgen::literals;

    // Connect to the database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        throw std::runtime_error("Failed to connect to database: " + 
                               conn_result.error().what());
    }
    auto conn = conn_result.value();

    // Build the base query
    auto query = sqlgen::read<std::vector<Book>>;

    // Conditionally add WHERE clauses based on provided filters
    auto condition = rfl::Nothing;

    if (filters.title_keyword) {
        condition = sqlgen::col<Book, "title">.like("%" + *filters.title_keyword);
    }

    if (filters.min_year) {
        if (condition) {
            condition = condition && (sqlgen::col<Book, "year"> >= *filters.min_year);
        } else {
            condition = sqlgen::col<Book, "year"> >= *filters.min_year;
        }
    }

    if (filters.genre) {
        if (condition) {
            condition = condition && (sqlgen::col<Book, "genre"> == *filters.genre);
        } else {
            condition = sqlgen::col<Book, "genre"> == *filters.genre;
        }
    }

    if (filters.max_price) {
        if (condition) {
            condition = condition && (sqlgen::col<Book, "price"> <= *filters.max_price);
        } else {
            condition = sqlgen::col<Book, "price"> <= *filters.max_price;
        }
    }

    // Apply the condition to the query
    if (condition != rfl::Nothing) {
        query = query | sqlgen::where(condition);
    }

    // Execute the query and return results
    auto result = query(conn);
    if (!result) {
        throw std::runtime_error("Query failed: " + result.error().what());
    }

    return result.value();
}

}  // namespace query_search_books_by_criteria

