```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

namespace generate_sql_dry_run {

struct A {
  sqlgen::PrimaryKey<int> id;
  std::string name;
};

struct B {
  sqlgen::PrimaryKey<int> id;
  int a_id;
  double score;
};

/**
 * This function demonstrates how to build a conditional SQL query.
 * It joins tables A and B, filtering for records where score > 10 and name contains 'x'.
 * Returns: std::string.
 */
std::string generate_sql_dry_run() {
    using namespace sqlgen::literals;

    // Build the query using sqlgen's fluent interface
    auto query = select_from<A, "t1">("id"_t1, "name"_t1, "score"_t2)
        | inner_join<B, "t2">("id"_t1 == "a_id"_t2)
        | where("score"_t2 > 10 && "name"_t1.like("%x%"))
        | order_by("score"_t2.desc())
        | limit(10);

    // Convert to SQL string using sqlite backend
    return sqlgen::sqlite::to_sql(query);
}

}  // namespace generate_sql_dry_run
```

## Explanation of the Implementation:

1. **Starting the query**: `select_from<A, "t1">("id"_t1, "name"_t1, "score"_t2)` starts building the query from table A with alias "t1" and selects specific fields.

2. **Join operation**: `| inner_join<B, "t2">("id"_t1 == "a_id"_t2)` performs an inner join with table B using alias "t2" and the join condition that A.id equals B.a_id.

3. **Where clause**: `| where("score"_t2 > 10 && "name"_t1.like("%x%"))` adds the filtering conditions:
   - B.score > 10
   - A.name contains 'x' (using LIKE operator)

4. **Ordering**: `| order_by("score"_t2.desc())` orders the results by B.score in descending order.

5. **Limiting results**: `| limit(10)` limits the output to 10 records.

6. **SQL generation**: `sqlgen::sqlite::to_sql(query)` converts the constructed query object into a SQL string for SQLite.

The function returns the generated SQL string, which would look something like:
```sql
SELECT t1.id, t1.name, t2.score 
FROM A AS t1 
INNER JOIN B AS t2 ON t1.id = t2.a_id 
WHERE t2.score > 10 AND t1.name LIKE '%x%' 
ORDER BY t2.score DESC 
LIMIT 10
```

