namespace analyze_social_network {

struct User {
    sqlgen::PrimaryKey<int> user_id;
    std::string username;
    std::string email;
    std::string join_date;
    std::string city;
};

struct Friendship {
    int user1_id;
    int user2_id;
    sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
    std::string user1_name;
    std::string user2_name;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
    using namespace sqlgen::literals;

    // Create database connection
    auto conn = sqlgen::sqlite::connect(":memory:");

    // Create tables
    conn->execute(R"(
        CREATE TABLE User (
            user_id INTEGER PRIMARY KEY,
            username TEXT NOT NULL UNIQUE,
            email TEXT NOT NULL UNIQUE,
            join_date TEXT NOT NULL,
            city TEXT
        )
    )");

    conn->execute(R"(
        CREATE TABLE Friendship (
            user1_id INTEGER,
            user2_id INTEGER,
            created_at TEXT,
            PRIMARY KEY (user1_id, user2_id),
            FOREIGN KEY (user1_id) REFERENCES User(user_id),
            FOREIGN KEY (user2_id) REFERENCES User(user_id)
        )
    )");

    // Insert data
    for (const auto& user : users) {
        conn->execute("INSERT INTO User VALUES (" +
                    std::to_string(user.user_id) + ", '" + user.username + "', '" + 
                    user.email + "', '" + user.join_date + "', '" + user.city + "');");
    }

    for (const auto& friendship : friendships) {
        conn->execute("INSERT INTO Friendship VALUES (" +
                    std::to_string(friendship.user1_id) + ", " + 
                    std::to_string(friendship.user2_id) + ", '" + 
                    friendship.created_at + "');");
    }

    // Query 1: Mutual friends using SELF-JOIN
    auto mutual_query = select_from<User, "u1"_t1>("username"_t1)
        | inner_join<Friendship, "f1"_t2>("u1"_t1("user_id") == "f1"_t2("user1_id"))
        | inner_join<User, "u2"_t3>("f1"_t2("user2_id") == "u2"_t3("user_id"))
        | where("u1"_t1("user_id") < "u2"_t3("user_id"))
        | group_by("u1"_t1("user_id"), "u2"_t3("user_id"))
        | having(count() > 0)
        | select("u1"_t1("username"), "u2"_t3("username"));

    // Query 2: Users with more than average friends using nested query
    auto avg_friends_subquery = select_from<User, "u"_t1>(count().as<"friend_count">())
        | group_by("u"_t1("user_id"));

    auto above_avg_query = select_from<User, "u"_t1>("user_id"_t1, "username"_t1)
        | left_join<Friendship, "f"_t2>("u"_t1("user_id") == "f"_t2("user1_id"))
        | group_by("u"_t1("user_id"), "u"_t1("username"))
        | having("friend_count"_t1 > (select_from(avg_friends_subquery).to<double>()))
        | order_by("friend_count"_t1.desc());

    // Query 3: Friend-of-friend relationships
    auto friend_of_friend_query = select_from<User, "u1"_t1>("username"_t1)
        | inner_join<Friendship, "f1"_t2>("u1"_t1("user_id") == "f1"_t2("user1_id"))
        | inner_join<Friendship, "f2"_t3>("f1"_t2("user2_id") == "f2"_t3("user1_id"))
        | inner_join<User, "u2"_t4>("f2"_t3("user2_id") == "u2"_t4("user_id"))
        | where("u1"_t1("user_id") != "u2"_t4("user_id"))
        | group_by("u1"_t1("user_id"), "u2"_t4("user_id"))
        | having(count() == 1)
        | select("u1"_t1("username"), "u2"_t4("username"));

    // Query 4: Count friends per user
    auto friends_count_query = select_from<User, "u"_t1>("user_id"_t1, "username"_t1)
        | left_join<Friendship, "f"_t2>("u"_t1("user_id") == "f"_t2("user1_id"))
        | group_by("u"_t1("user_id"), "u"_t1("username"))
        | select("user_id"_t1, "username"_t1, count().as<"friend_count">());

    // Query 5: Same city recommendations
    auto same_city_recommendations = select_from<User, "u1"_t1>("username"_t1)
        | inner_join<User, "u2"_t2>("u1"_t1("city") == "u2"_t2("city"))
        | where("u1"_t1("user_id") != "u2"_t2("user_id"))
        | and_where(not_exists(select_from<Friendship>("user1_id"_t1, "user2_id"_t2)
            .where("user1_id"_t1 == "u1"_t1("user_id"))
            .where("user2_id"_t2 == "u2"_t2("user_id"))))
        | select("u1"_t1("username"), "u2"_t2("username"));

    // Execute all queries and collect results
    std::vector<FriendConnection> results;

    // Execute mutual friends query
    auto mutual_result = mutual_query(conn);
    for (auto& row : mutual_result) {
        results.emplace_back(FriendConnection{
            .user1_name = row["u1_username"].get<std::string>(),
            .user2_name = row["u2_username"].get<std::string>()
        });
    }

    // Execute friend-of-friend query
    auto friend_of_friend_result = friend_of_friend_query(conn);
    for (auto& row : friend_of_friend_result) {
        results.emplace_back(FriendConnection{
            .user1_name = row["u1_username"].get<std::string>(),
            .user2_name = row["u2_username"].get<std::string>()
        });
    }

    // Execute same city recommendations
    auto recommendations_result = same_city_recommendations(conn);
    for (auto& row : recommendations_result) {
        results.emplace_back(FriendConnection{
            .user1_name = row["u1_username"].get<std::string>(),
            .user2_name = row["u2_username"].get<std::string>()
        });
    }

    return results;
}

}  // namespace analyze_social_network

